import Icon from '../../components/common/Icon';
import { iconCategories } from '../../config/icons';
import { useNotifier } from '../../context/NotificationContext';

const Objects = () => {
    const { notify } = useNotifier();

    const handleCopy = (name) => {
        navigator.clipboard.writeText(name);
        notify({
            title: 'Copied!',
            message: `Icon name "${name}" copied to clipboard`,
            style: 'success',
            duration: 2000
        });
    };

    return (
        <div className='admin-pager'>
            <header className='admin-pager-head'>
                <div className='admin-pager-title'> <span><h2>System Icons</h2><p>Categorized Lucide Icons</p></span>  </div>
            </header>

            <div className='pagelet'><div className='pagelet-in'>
                <div className='template-icons-wrap'>
                    {Object.entries(iconCategories).map(([category, items]) => (
                        <div key={category} className='template-icons-item' >
                            <h4>{category}</h4>
                            <div className='template-icons'>
                                {Object.entries(items).map(([name, icon]) => (
                                    <button key={name} title={`Double click to copy: ${name}`} onDoubleClick={() => handleCopy(name)} > <Icon icon={icon} /> </button>
                                ))}
                            </div>
                        </div>
                    ))}
                </div>
            </div></div>
        </div>);
};
export default Objects;